import tech.robd.notnull.LocalNotNull;
import tech.robd.notnull.NotNull;

public class Foo {
    public void bar(String value) {
        final @LocalNotNull String name = NotNull.verify(value);
    }
}

import tech.robd.notnull.LocalNotNull;
import tech.robd.notnull.NotNull;

public class Foo {
    public void bar(String value) {
        final @LocalNotNull String name = NotNull.orThrow(value);
    }
}

import tech.robd.notnull.LocalNotNull;
import tech.robd.notnull.NotNull;

public class Foo {
    public void bar(String value) {
        final @LocalNotNull String name = NotNull.orDefault(value, "default");
    }
}

import tech.robd.notnull.LocalNotNull;
import tech.robd.notnull.NotNull;
import java.util.List;

public class Foo {
    public void bar(List<String> value) {
        final @LocalNotNull List<String> items = NotNull.listOrEmpty(value);
    }
}

import tech.robd.notnull.LocalNotNull;

public class Foo {
    public void bar() {
        final @LocalNotNull String name;
    }
}

import tech.robd.notnull.LocalNotNull;

public class Foo {
    public void bar(String value) {
        final @LocalNotNull String name = value;
    }
}

import tech.robd.notnull.LocalNotNull;
import tech.robd.notnull.NotNull;
import java.util.Optional;

public class Foo {
    public void bar(Optional<String> opt) {
        final @LocalNotNull String name = NotNull.orNull(opt);
    }
}

import tech.robd.notnull.LocalNotNull;
import tech.robd.notnull.NotNull;

public class Foo {
    public void bar(String value) {
        final @LocalNotNull String name = NotNull.orLogGet(value, () -> "fallback", "ctx");
    }
}

import tech.robd.notnull.LocalNotNull;
import tech.robd.notnull.NotNull;

public class Foo {
    public void bar(String value, String other) {
        final @LocalNotNull String name = NotNull.verify(value);
        name = other;  // Violation: reassignment without NotNull method
    }
}

import tech.robd.notnull.LocalNotNull;
import tech.robd.notnull.NotNull;

public class Foo {
    public void bar(String value, String other) {
        final @LocalNotNull String name = NotNull.verify(value);
        name = NotNull.verify(other);
    }
}
